CREATE procedure [dbo].[Categories_Add]
@name nvarchar(30),@status bit
as
insert into Categories(Cat_ID,Cat_Name,Cat_Status) values((select isnull(max(Cat_ID)+1,1) from Categories),@name,@status);
return
GO
