CREATE Proc [dbo].[Products_Select_Search]	
@Search nvarchar(50)
as
if(@Search='')
SELECT [P_ID] as 'ID'
	  ,[P_Name] as 'Name'
	  ,[Barcode] as 'Barcode'
      ,[buyPrice] as 'Buy Price'
      ,[sellPrice] as 'Sell Price'
      ,[P_Filling] as 'Fill'
      ,[P_Filling_Price] as 'Fill Price'
      ,c.Cat_Name as 'Categories'
      ,s.Sn_Name as 'Scientfic Name'
      ,pc.Com_Name as 'Producer Company'
      ,[P_Description] as 'Description'
      ,[P_active] as 'State'
      
  FROM Products p,Categories c,Sceintific_Name s,Producer_Company pc
where p.Cat_ID=c.Cat_ID and p.Com_ID=pc.Com_ID and p.Sn_ID=s.Sn_ID
else
SELECT [P_ID] as 'ID'
	  ,[P_Name] as 'Name'
	  ,[Barcode] as 'Barcode'
      ,[buyPrice] as 'Buy Price'
      ,[sellPrice] as 'Sell Price'
      ,[P_Filling] as 'Fill'
      ,[P_Filling_Price] as 'Fill Price'
      ,c.Cat_Name as 'Categories'
      ,s.Sn_Name as 'Scientfic Name'
      ,pc.Com_Name as 'Producer Company'
      ,[P_Description] as 'Description'
      ,[P_active] as 'State'
  FROM Products p,Categories c,Sceintific_Name s,Producer_Company pc
where p.Cat_ID=c.Cat_ID and p.Com_ID=pc.Com_ID and p.Sn_ID=s.Sn_ID
and P_Name+P_Description+Barcode+c.Cat_Name+s.Sn_Name+pc.Com_Name Like  '%'+@Search+'%'
return

GO
