CREATE procedure [dbo].[Sales_Details_Insert]
@Sales_ID int,@Product_ID int,@Price nvarchar(30),@Qty int,@Total nvarchar(30),
@Discount nvarchar(30),@Notes nvarchar(100)
as
insert into Sales_Details(SalesDet_ID,Sales_ID,Product_ID,SalesDet_Price,SalesDet_Qty,SalesDet_Total,SalesDet_Discount,SalesDet_Notes)
values((select ISNULL(MAX(SalesDet_ID)+1,1) from Sales_Details),@Sales_ID,@Product_ID,@Price,@Qty,@Total,@Discount,@Notes);

--declare @product cursor
--set @product= cursor for (select Product_ID,SalesDet_Qty from Sales_Details where Product_ID=@Product_ID)
--open @product
--declare @P_ID int,@Qt varchar(50)
--fetch @product into @P_ID,@Qt
--while @@FETCH_STATUS=0
--begin

declare @expired cursor
set @expired=cursor for select Ex_Date,Qty from ExpAndQty where P_ID=@Product_ID
and convert(float,Qty)>0
order by Ex_Date

open @expired

declare @ex_Date datetime,@ex_Qty int

fetch @expired into @ex_Date,@ex_Qty
while @@FETCH_STATUS=0
begin
if(CONVERT(float,@Qty)<=CONVERT(float,@ex_Qty))
begin
update ExpAndQty set Qty=CONVERT(int,Qty)-CONVERT(int,@Qty)
where P_ID=@Product_ID and Ex_Date=@ex_Date

break

end

else
begin

update ExpAndQty set Qty=0 where P_ID=@Product_ID and Ex_Date=@ex_Date
set @Qty=CONVERT(int,@Qty)-CONVERT(int,@ex_Qty)
end
fetch @expired into @ex_Date,@ex_Qty
end


return
GO
