create procedure [dbo].[Sales_Insert]
@Date datetime,@Cust_ID int,@Notes nvarchar(100),@User_Added nvarchar(30),@Count int,@Discount int,
@Paid nvarchar(50),@Residul nvarchar(50),@Amount nvarchar(50),@Total nvarchar(50)
as
INSERT INTO Sales
           ([Sales_ID]
           ,[Sales_Date]
           ,[Cust_ID]
           ,[Sales_Notes]
           ,[Sales_User_Added]
           ,[Sales_Count]
           ,[Sales_Total_Discount]
           ,[Sales_Total_Paid]
           ,[Sales_Total_Residul]
           ,[Sales_Total_Amount]
           ,[Sales_Total])
     VALUES
           ((select ISNULL(MAX(Sales_ID)+1,1) from Sales)
           ,@Date
           ,@Cust_ID
           ,@Notes
           ,@User_Added
           ,@Count
           ,@Discount
           ,@Paid
           ,@Residul
           ,@Amount
           ,@Total)



