CREATE procedure [dbo].[Stack_Select]
@Search nvarchar(50)
as
if(@Search='')

SELECT ex.Ex_ID as 'ID'
	  ,[P_Name] as 'Name'
	  ,[Barcode] as 'Barcode'
	  ,ex.Qty as 'quntity'
     ,convert(datetime,ex.Ex_Date) as 'Expired Date'
      ,sup.Su_Name as 'Supplier'
      ,[buyPrice] as 'Buy Price'
      ,[sellPrice] as 'Sell Price'
      ,[P_Filling] as 'Filling'
      ,[P_Filling_Price] as 'Filling Price'
      ,c.Cat_Name as 'Categories'
      ,s.Sn_Name as 'Scientfic Name'
      ,pc.Com_Name as 'Producer Company'
      ,[P_Description] as 'Description'
      ,[P_active] as 'State'
 
  FROM 
  Products p,
  Categories c,
  Sceintific_Name s,
  Producer_Company pc,
  ExpAndQty ex,
  Suppliers sup
where p.Cat_ID=c.Cat_ID and p.Com_ID=pc.Com_ID and p.Sn_ID=s.Sn_ID and p.P_ID=ex.P_ID and ex.Supplier_ID=sup.Su_ID

else

SELECT ex.Ex_ID as 'ID'
	  ,[P_Name] as 'Name'
	  ,[Barcode] as 'Barcode'
	  ,ex.Qty as 'quntity'
     ,convert(datetime,ex.Ex_Date) as 'Expired Date'
      ,sup.Su_Name as 'Supplier'
      ,[buyPrice] as 'Buy Price'
      ,[sellPrice] as 'Sell Price'
      ,[P_Filling] as 'Filling'
      ,[P_Filling_Price] as 'Filling Price'
      ,c.Cat_Name as 'Categories'
      ,s.Sn_Name as 'Scientfic Name'
      ,pc.Com_Name as 'Producer Company'
      ,[P_Description] as 'Description'
      ,[P_active] as 'State'
 
  FROM 
  Products p,
  Categories c,
  Sceintific_Name s,
  Producer_Company pc,
  ExpAndQty ex,
  Suppliers sup
where
p.Cat_ID=c.Cat_ID 
and p.Com_ID=pc.Com_ID 
and p.Sn_ID=s.Sn_ID 
and p.P_ID=ex.P_ID 
and ex.Supplier_ID=sup.Su_ID
and P_Name+P_Description+Barcode+c.Cat_Name+s.Sn_Name+pc.Com_Name Like  '%'+@Search+'%'

GO
