create procedure [dbo].[Users_Add]
@name nvarchar(30),@pass nvarchar(60),@full_name nvarchar(30),@Per_ID int
as
insert into Users(U_ID,U_Name,U_Pass,U_Full_Name,Per_ID) 
values((select ISNULL(MAX(U_ID)+1,1) from Users),@name,@pass,@full_name,@Per_ID)
