create procedure [dbo].[Users_Select]
as
select U_ID as 'ID',
U_Name as 'Name',
U_Full_Name as 'Full Name',
U_Pass as 'Password',
p.Per_Name as 'Type'
 from [Users] s,[Permissions] p where s.Per_ID=p.Per_ID
 return
