create procedure [dbo].[Users_Update]
@ID int,@name nvarchar(30),@pass nvarchar(60),@full_name nvarchar(30),@Per_ID int
as
update Users set U_Name=@name,U_Pass=@pass,U_Full_Name=@full_name,Per_ID=@Per_ID where U_ID=@ID;
return;
